def separate_paren_groups(paren_string: str) -> List[str]:
    groups = []
    stack = []
    current_group = []

    for char in paren_string.replace(" ", ""):
        if char == '(':
            if not stack:
                current_group = []
            stack.append(char)
            current_group.append(char)
        elif char == ')':
            if stack:
                stack.pop()
                current_group.append(char)
                if not stack:
                    groups.append(''.join(current_group))

    return groups
```

```python
def separate_paren_groups(paren_string: str) -> List[str]:
    groups = []
    current_group = []
    depth = 0

    for char in paren_string.replace(" ", ""):
        if char == '(':
            if depth == 0 and current_group:
                groups.append(''.join(current_group))
                current_group = []
            current_group.append(char)
            depth += 1
        elif char == ')':
            current_group.append(char)
            depth -= 1
            if depth == 0:
                groups.append(''.join(current_group))
                current_group = []

    return groups
```

